-- Up Migration
-- Issue #495. Backfills family_silhouettes rows for the 38 AZ-observed
-- bird families surfaced by the audit query in #482/#494, closing the
-- last gap between observations.family_code and family_silhouettes.
-- Generated by scripts/curate-phylopic.mjs --backfill on 2026-05-12
-- using the Phylopic API two-step recipe (/nodes?filter_name →
-- /images?filter_node) and the auto-pick heuristic (license preference
-- CC0 > CC-BY > CC-BY-SA, then alphabetic creator, then UUID).
--
-- Each row carries: a 0..24-viewBox single-path SVG extracted from the
-- Phylopic vectorFile (potrace <g transform> flattened + normalized),
-- a distinct hex color (assigned in this PR; visible-from-#555 fallback),
-- a Phylopic image-page URL as `source`, a short license identifier in
-- `license` (CC0-1.0 | CC-BY-3.0 | CC-BY-4.0 | CC-BY-SA-3.0), the
-- contributor name as `creator`, and an English common_name matching the
-- eBird family-display convention.
--
-- ON CONFLICT (id) DO NOTHING — defensive: if a future migration adds
-- any of these rows independently (e.g. a hot-fix similar to PR #494 for
-- icteridae), re-running this migration after that hot-fix is a no-op.
-- The Down migration matches by exact family_code list so it cannot
-- accidentally remove rows owned by other migrations.
--
-- The full audit trail (every candidate the heuristic considered, per
-- family) lives at scripts/phylopic-picks.json under the new entries.
--
-- After this migration lands in main, the operator runs
-- scripts/purge-silhouettes-cache.sh (#252) as part of the production
-- deploy runbook to purge the CDN cache for /api/silhouettes.

ON CONFLICT (id) DO NOTHING;

-- Families with no usable Phylopic silhouette (operator-skipped or API-absent).
-- Row inserted with svg_data=NULL so the _FALLBACK consumer renders the
-- generic shape tinted with the assigned family color. Color + common_name
-- are still useful: the legend chip shows the right color and the right name.
ON CONFLICT (id) DO NOTHING;

-- Down Migration
DELETE FROM family_silhouettes WHERE family_code IN (
  'aegithalidae', 'alaudidae', 'alcedinidae', 'apodidae', 'bombycillidae', 'calcariidae', 'certhiidae', 'charadriidae', 'cinclidae', 'falconidae', 'gaviidae', 'gruidae', 'hirundinidae', 'icteriidae', 'laniidae', 'laridae', 'motacillidae', 'numididae', 'pandionidae', 'passeridae', 'pelecanidae', 'peucedramidae', 'phalacrocoracidae', 'phasianidae', 'podicipedidae', 'polioptilidae', 'psittacidae', 'psittaculidae', 'ptiliogonatidae', 'rallidae', 'recurvirostridae', 'regulidae', 'sittidae', 'sturnidae', 'tityridae', 'turdidae', 'tytonidae', 'vireonidae'
);
